async function main() {
  const target = await api.getTargetSite();
  const raw = String(target);
  const siteUrl = raw.match(/^https?:\/\//) ? raw : `https://${raw}`;

  const findings:any[] = [];
  const pages = ['/', '/about', '/contact', '/pricing', '/login', '/signup'];

  for (const path of pages) {
    try {
      const report = await api.auditSite({ siteUrl: new URL(path, siteUrl).toString() });
      if (report && Array.isArray(report.findings)) {
        for (const f of report.findings) findings.push(f);
      }
    } catch (e) {}
  }

  const unique = new Map<string, any>();
  for (const f of findings) {
    const key = [f.severity, f.title, f.location, f.description].join('|');
    if (!unique.has(key)) unique.set(key, f);
  }

  const deduped = Array.from(unique.values()).slice(0, 8).map((f:any) => ({
    severity: f.severity || 'low',
    title: f.title || 'UI/UX issue',
    description: f.description || 'Issue detected during page audit.',
    location: f.location || siteUrl,
    suggestedFix: f.suggestedFix || 'Review the affected UI and improve usability.',
  }));

  const summary = `Audited ${pages.length} key pages and identified ${deduped.length} prioritized UI/UX issues.`;

  return { siteUrl, findings: deduped, summary };
}
return await main();

